const MAX = 100;
type TStiva = record
  elem: array[1..MAX] of integer;
  vf: integer;
end;

procedure Init(var s: TStiva);
begin
  s.vf := 0;
end;

function EsteGoala(s: TStiva): boolean;
begin
  EsteGoala := (s.vf = 0);
end;

procedure Push(var s: TStiva; x: integer);
begin
  if s.vf < MAX then
  begin
    s.vf := s.vf + 1;
    s.elem[s.vf] := x;
  end
  else writeln('Stiva plina');
end;

function Pop(var s: TStiva): integer;
begin
  if not EsteGoala(s) then
  begin
    Pop := s.elem[s.vf];
    s.vf := s.vf - 1;
  end
  else writeln('Stiva goala');
end;

var s: TStiva;
begin
  Init(s);
  Push(s, 10);
  Push(s, 20);
  writeln(Pop(s)); // Afișează 20
end.

int fact(int n) {
  if (n <= 1) return 1; // caz de bază
  return n * fact(n-1); // pas recursiv
}

int fib(int n) {
  if (n <= 1) return n;
  return fib(n-1) + fib(n-2);
}

int sum_cif(int n) {
  if (n == 0) return 0;
  return (n % 10) + sum_cif(n / 10);
}

