#include <iostream>
#include <vector>
using namespace std;
void backtrack(vector<int>& perm, vector<bool>& used, int n) {
    if (perm.size() == n) {
        for (int num : perm) cout << num << ' ';
        cout << endl;
        return;
    }
    for (int i = 1; i <= n; i++) {
        if (!used[i]) {
            used[i] = true;
            perm.push_back(i);
            backtrack(perm, used, n);
            perm.pop_back();
            used[i] = false;
        }
    }
}

